    const defaults = plot3d.createRotationState({
      x: SCATTER_3D_DEFAULTS.rotationX,
      y: SCATTER_3D_DEFAULTS.rotationY
    });
    scatterState.rotation.x = defaults.x;
    scatterState.rotation.y = defaults.y;
