      const r2 = 1 - (sse / sst);
      const statistic = Math.max(0, n * Math.max(0, r2));
      const pValue = (jStatApi?.chisquare && Number.isFinite(statistic))
        ? (1 - jStatApi.chisquare.cdf(statistic, 1))
        : NaN;
