              add('line',{
                x1: yAxisX - breakCapHalfLen,
                y1: segBottom,
                x2: yAxisX + breakCapHalfLen,
                y2: segBottom,
                stroke: axisStroke,
                'stroke-width': axisStrokeWidth
              });
              yBreakCapCount += 1;
